import UIKit

class StockTradingApp: UIViewController {
    
    // MARK: - Outlets
    @IBOutlet weak var tradeButton: UIButton!
    @IBOutlet weak var portfolioTableView: UITableView!
    
    // MARK: - Properties
    let apiManager = APIManager()
    var stocks = [Stock]()
    
    // MARK: - View Life Cycle
    override func viewDidLoad() {
        super.viewDidLoad()
        
        // Set up the table view for portfolio management
        portfolioTableView.dataSource = self
        portfolioTableView.delegate = self
        
        // Load initial data from API
        apiManager.fetchStocks { [weak self] stocks in
            guard let self = self else { return }
            self.stocks = stocks
            self.portfolioTableView.reloadData()
        }
    }
    
    // MARK: - IBActions
    @IBAction func tradeButtonTapped(_ sender: UIButton) {
        // Implement trade execution functionality here
        let selectedStock = stocks[0] // for demo purpose only
        apiManager.executeTrade(stock: selectedStock) { [weak self] result in
            guard let self = self else { return }
            switch result {
            case .success(let response):
                print("Trade executed successfully")
            case .failure(let error):
                print("Error executing trade: \(error)")
            }
        }
    }
}

extension StockTradingApp: UITableViewDataSource, UITableViewDelegate {
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return stocks.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "stockCell", for: indexPath) as! StockTableViewCell
        let stock = stocks[indexPath.row]
        cell.configure(with: stock)
        return cell
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        // Handle stock selection here
        let selectedStock = stocks[indexPath.row]
        apiManager.fetchStockDetails(for: selectedStock.symbol) { [weak self] result in
            guard let self = self else { return }
            switch result {
            case .success(let response):
                print("Fetched stock details successfully")
            case .failure(let error):
                print("Error fetching stock details: \(error)")
            }
        }
    }
}